// Parse the health scan response and extract the machine-readable summary
const body = $input.first().json;

// MCP returns: { result: { content: [{ type: 'text', text: '...' }] } }
const text = body?.result?.content?.[0]?.text ?? body?.content?.[0]?.text ?? JSON.stringify(body);

// Extract SCAN_RESULT JSON embedded in the response
const match = text.match(/SCAN_RESULT:({.*})/);
if (!match) {
  return [{
    json: {
      success: false,
      error: 'Could not parse SCAN_RESULT from health scan response',
      rawText: text.slice(0, 500),
      critical: 0,
      tierDrops: 0,
      scanned: 0,
    }
  }];
}

let summary;
try {
  summary = JSON.parse(match[1]);
} catch (e) {
  return [{
    json: {
      success: false,
      error: `JSON parse failed: ${e.message}`,
      rawMatch: match[1].slice(0, 300),
      critical: 0,
      tierDrops: 0,
      scanned: 0,
    }
  }];
}

return [{
  json: {
    success: true,
    date: summary.date,
    scanned: summary.scanned,
    healthy: summary.healthy,
    watch: summary.watch,
    atRisk: summary.atRisk,
    critical: summary.critical,
    tierDrops: summary.tierDrops,
    tasksCreated: summary.tasksCreated,
    dryRun: summary.dryRun,
    criticalAccounts: summary.criticalAccounts ?? [],
    tierDropAccounts: summary.tierDropAccounts ?? [],
    // Formatted Slack message for critical alert
    slackCriticalMessage: summary.critical > 0
      ? [
          `🚨 *Foresight Nightly Scan — ${summary.date}*`,
          ``,
          `*${summary.critical} account(s) in CRITICAL tier* require immediate AM attention:`,
          ...(summary.criticalAccounts ?? []).map(a =>
            `• *${a.name}* — Score: ${a.score}${a.mrr ? ` | $${a.mrr.toLocaleString()}/mo` : ''} — AM: ${a.amName}${a.dropped ? ' ⬇️ dropped this scan' : ''}`
          ),
          ``,
          `_${summary.scanned} accounts scanned | ${summary.tierDrops} tier drop(s) | ${summary.tasksCreated} task(s) created_`,
        ].join('\n')
      : null,
    // Formatted Slack message for tier drop alert (non-critical)
    slackDropMessage: summary.tierDrops > 0 && summary.critical === 0
      ? [
          `⚠️ *Foresight Nightly Scan — ${summary.date}*`,
          ``,
          `*${summary.tierDrops} account(s) dropped tier* — no Critical accounts:`,
          ...(summary.tierDropAccounts ?? []).map(a =>
            `• *${a.name}* — ${a.oldTier} → *${a.newTier}* — AM: ${a.amName}`
          ),
          ``,
          `_${summary.scanned} accounts scanned | AM Tasks created in Salesforce_`,
        ].join('\n')
      : null,
    // Summary for daily log (always posted)
    slackLogMessage: [
      `✅ *Foresight Scan Complete — ${summary.date}*`,
      `${summary.scanned} accounts | 🟢 ${summary.healthy} Healthy | 🟡 ${summary.watch} Watch | 🟠 ${summary.atRisk} At Risk | 🔴 ${summary.critical} Critical`,
      summary.tierDrops > 0
        ? `⚠️ ${summary.tierDrops} tier drop(s) detected — ${summary.tasksCreated} AM task(s) created`
        : `No tier drops — all accounts holding steady`,
    ].join('\n'),
  }
}];
